mapper.select:
SELECT s.staff_id AS staffId, s.staff_name AS name, s.staff_role AS role, s.staff_contact AS contact, d.department_name AS department, s.status AS status FROM staff s LEFT JOIN department d ON s.department_id = d.department_id
AND s.staff_name LIKE CONCAT('%', #{name}, '%')
AND d.department_name = #{department}
AND s.staff_role = #{role}
AND s.status = #{status}
ORDER BY s.staff_id DESC
